body {
    background-color: #0f172a;
    color: #f8fafc;
    font-family: sans-serif;
    padding: 2rem;
    text-align: center;
}

h1 {
    color: #38bdf8;
}

button {
    background-color: #38bdf8;
    border: none;
    border-radius: 0.5rem;
    color: #0f172a;
    cursor: pointer;
    font-weight: bold;
    padding: 0.5rem 1rem;
    transition: background-color 0.2s;
}

button:hover {
    background-color: #7dd3fc;
}

console.log("Hallo vanuit de console!");

const knop = document.getElementById("knop");
const tekst = document.getElementById("tekst");

if (knop) {
    knop.addEventListener("click", () => {
        console.log("Er is op de knop geklikt!");
        if (tekst) {
            tekst.textContent = "Je hebt succesvol de JavaScript interactie getest!";
            tekst.style.color = "#4ade80";
        }
    });
}

